        count = sum(1 for num in nums if num == 0)
        start = (len(nums) - count) // 3
        temp = {}
        first_third = int((len(nums)) / 3)
        for num in nums:
            if num in temp:
                temp[num] += 1
            else:
                temp[num] = 1
        res = [0]*first_third + [1]*first_third + [2]*count
